def review_summary():
    products = {}
    summary = {}
    highest_avg_product = None
    lowest_avg_product = None
    highest_avg_rating = 0
    lowest_avg_rating = None

    n = int(input())
    for i in range(n):
        product_id = int(input())
        name = input()
        category = input()
        r = int(input())

        reviews = []
        for i in range(r):
            reviewer, rating = input().split()
            reviews.append({'reviewer': reviewer, 'rating': int(rating)})

        products[product_id] = {'name': name, 'category': category, 'reviews': reviews}

    for product_id, details in products.items():
        reviews = details['reviews']
        if reviews:
            avg_rating = sum(review['rating'] for review in reviews) / len(reviews)
            summary[details['name']] = avg_rating

            if avg_rating > highest_avg_rating:
                highest_avg_rating = avg_rating
                highest_avg_product = details['name']

            if lowest_avg_rating is None or avg_rating < lowest_avg_rating: 
                lowest_avg_rating = avg_rating
                lowest_avg_product = details['name']

    result = {
        'summary': summary,
        'highest_avg_product': highest_avg_product,
        'lowest_avg_product': lowest_avg_product
    }
    return result
result = review_summary()
print(result)
